create extension if not exists pgcrypto;
create type public.user_role as enum ('user','admin');
create type public.audit_status as enum ('queued','running','completed','failed','cancelled');
create table public.profiles (id uuid primary key references auth.users on delete cascade, email text, display_name text, role user_role not null default 'user', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.projects (id uuid primary key default gen_random_uuid(), owner_id uuid not null references auth.users on delete cascade, name text not null, description text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.outcome_contracts (id uuid primary key default gen_random_uuid(), owner_id uuid not null references auth.users on delete cascade, project_id uuid references public.projects on delete set null, version text not null, title text not null, original_task text not null, task_type text not null check(task_type in ('website','repository','content','mixed')), status text not null check(status in ('draft','locked')), contract_json jsonb not null, contract_hash text, created_at timestamptz not null default now(), locked_at timestamptz, updated_at timestamptz not null default now(), check(status <> 'locked' or contract_hash ~ '^[0-9a-f]{64}$'));
create table public.audits (id uuid primary key default gen_random_uuid(), owner_id uuid not null references auth.users on delete cascade, project_id uuid references public.projects on delete set null, contract_id uuid not null references public.outcome_contracts, status audit_status not null default 'queued', target_type text not null, target_reference text not null, completion_score numeric, confidence_score numeric, verdict text, recommended_action text, started_at timestamptz, completed_at timestamptz, created_at timestamptz not null default now());
create table public.test_results (id uuid primary key default gen_random_uuid(), audit_id uuid not null references public.audits on delete cascade, test_id text not null, status text not null, severity text not null, objective boolean not null, summary text not null, expected_json jsonb, actual_json jsonb, evidence_json jsonb not null default '[]', duration_ms integer not null, created_at timestamptz not null default now());
create table public.proof_receipts (id uuid primary key default gen_random_uuid(), audit_id uuid unique not null references public.audits on delete cascade, receipt_json jsonb not null, contract_hash text not null, evidence_hash text not null, public_slug text unique, is_public boolean not null default false, created_at timestamptz not null default now());
create table public.api_usage (id bigint generated always as identity primary key, api_key_hash text, endpoint text not null, request_id text not null, status_code integer not null, latency_ms integer not null, created_at timestamptz not null default now());
create table public.system_events (id bigint generated always as identity primary key, event_type text not null, severity text not null, correlation_id text not null, redacted_payload jsonb not null default '{}', created_at timestamptz not null default now());
alter table public.profiles enable row level security; alter table public.projects enable row level security; alter table public.outcome_contracts enable row level security; alter table public.audits enable row level security; alter table public.test_results enable row level security; alter table public.proof_receipts enable row level security; alter table public.api_usage enable row level security; alter table public.system_events enable row level security;
create policy "own profile" on public.profiles for all using (id=auth.uid()) with check(id=auth.uid());
create policy "own projects" on public.projects for all using(owner_id=auth.uid()) with check(owner_id=auth.uid());
create policy "own contracts" on public.outcome_contracts for all using(owner_id=auth.uid()) with check(owner_id=auth.uid());
create policy "own audits" on public.audits for all using(owner_id=auth.uid()) with check(owner_id=auth.uid());
create policy "own results" on public.test_results for select using(exists(select 1 from public.audits a where a.id=audit_id and a.owner_id=auth.uid()));
create policy "own receipts" on public.proof_receipts for all using(exists(select 1 from public.audits a where a.id=audit_id and a.owner_id=auth.uid())) with check(exists(select 1 from public.audits a where a.id=audit_id and a.owner_id=auth.uid()));
create policy "public receipt envelope" on public.proof_receipts for select using(is_public=true and public_slug is not null);
-- api_usage and system_events intentionally have no client policy; server service-role only.
create or replace function public.prevent_locked_contract_changes() returns trigger language plpgsql as $$ begin if old.status='locked' and new.contract_json is distinct from old.contract_json then raise exception 'locked contracts are immutable; create a new version'; end if; return new; end $$;
create trigger immutable_locked_contract before update on public.outcome_contracts for each row execute function public.prevent_locked_contract_changes();
